// Programmatic profiling
import { Profiler } from 'react';

function App() {
  const logRender = (id, phase, actualDuration) => {
    console.table({ id, phase, duration: `${actualDuration.toFixed(2)}ms` });
  };

  return (
    <Profiler id="App" onRender={logRender}>
      <MainApp />
    </Profiler>
  );
}
